<script setup lang="ts">import {computed,onMounted,ref} from 'vue'; import Message from 'primevue/message'; import Tag from 'primevue/tag'; import {useAuthStore} from '../../../stores/auth'; import {useCrmStore} from '../../../stores/crm'; const auth=useAuthStore(),crm=useCrmStore(),error=ref(''); const active=computed(()=>crm.myProspects.filter(v=>!['LOST','CONVERTED'].includes(v.status))); const completed=computed(()=>crm.myProspects.filter(v=>['WON','LOST','CONVERTED'].includes(v.status)).length); onMounted(async()=>{try{await Promise.all([crm.loadMyProspects(),crm.loadMyCustomers()])}catch(e){error.value=crm.errorMessage(e)}})</script>
<template><section class="sales-home"><Message v-if="error" severity="error">{{ error }}</Message><RouterLink class="ready-card" to="/sales/my-prospects"><div><strong>Your day is ready</strong><span>{{ active.length }} prospects assigned · First follow-up at 09:30</span></div><i class="pi pi-arrow-right" /></RouterLink><div class="section-title"><strong>Quick statistics</strong><RouterLink to="/sales/history">View all</RouterLink></div><div class="quick-stats"><RouterLink to="/sales/my-customers"><span class="blue-dot">C</span><strong>{{ crm.myCustomers.length }}</strong><small>Today's customers</small></RouterLink><RouterLink to="/sales/my-prospects"><span class="amber-dot">P</span><strong>{{ active.length }}</strong><small>Today's prospects</small></RouterLink><RouterLink to="/sales/history"><span class="green-dot"><i class="pi pi-check" /></span><strong>{{ completed }}</strong><small>Completed outcomes</small></RouterLink><RouterLink to="/sales/my-prospects"><span class="red-dot"><i class="pi pi-clock" /></span><strong>{{ active.filter(v=>v.status==='NEGOTIATION').length }}</strong><small>Pending decisions</small></RouterLink></div><div class="section-title"><strong>Quick actions</strong></div><div class="quick-actions"><RouterLink to="/sales/my-prospects"><i class="pi pi-play" /><span>Start visit</span></RouterLink><RouterLink to="/sales/my-prospects"><i class="pi pi-map" /><span>Open map</span></RouterLink><RouterLink to="/sales/my-customers"><i class="pi pi-users" /><span>Customer</span></RouterLink><RouterLink to="/sales/my-prospects"><i class="pi pi-briefcase" /><span>Prospect</span></RouterLink></div><div class="section-title"><strong>Today's visits</strong><RouterLink to="/sales/my-prospects">See route</RouterLink></div><div class="today-list"><RouterLink v-for="(item,index) in active.slice(0,3)" :key="item.id" :to="`/sales/my-prospects/${item.id}`"><time>{{ `${9+index}:30` }}<small>Today</small></time><i class="visit-dot" /><div><strong>{{ item.placeName }}</strong><small>{{ item.industryGroup }} · {{ item.assignedSalesExecutive }}</small></div><Tag :value="item.status.replaceAll('_',' ')" severity="warn" /></RouterLink><div v-if="!active.length" class="empty-state"><strong>No visits queued</strong></div></div></section></template>
